"use client";

import { useEffect, useState } from "react";
import { fetchAirQuality } from "./lib/fetchAirQuality";

export default function Home() {
  const [aqi, setAqi] = useState<number | null>(null);

  useEffect(() => {
    fetchAirQuality("pristina").then((data) => setAqi(data.aqi));
  }, []);

  return (
    <main className="p-10">
      <h1 className="text-3xl font-bold mb-4">Kosovo Air Quality Dashboard</h1>
      <p>{aqi !== null ? `AQI Prishtinë: ${aqi}` : "Loading..."}</p>
    </main>
  );
}
